const where = filters.length ? `WHERE ${filters.join(' AND ')}` : '';
const orderBy = d.action === 'low_stock'
  ? 'ORDER BY stock ASC, item_name ASC'
  : d.action === 'search'
    ? `ORDER BY CASE WHEN LOWER(item_name) = LOWER('${esc(d.search_term)}') THEN 0 WHEN item_name ILIKE '${esc(d.search_term)}%' THEN 1 ELSE 2 END, item_name ASC`
    : 'ORDER BY item_name ASC';
const limit = d.action === 'list' ? 25 : 10;
return [{ json: { ...d, sql: `SELECT ${selectCols.join(', ')} FROM public.inventory ${where} ${orderBy} LIMIT ${limit};` } }];

